sql:
SELECT sample_name
FROM genomics_samples
WHERE dataset_id = 1;

SELECT DISTINCT scientific_name
FROM genomics_samples
ORDER BY scientific_name;

SELECT sample_type, COUNT(*) AS sample_count
FROM genomics_samples
GROUP BY sample_type;

SELECT AVG(sample_count) AS average_samples_per_dataset
FROM (
  SELECT dataset_id, COUNT(sample_id) AS sample_count
  FROM genomics_samples
  GROUP BY dataset_id
) AS sample_counts;

external_knowledge:
- 'mature samples' refers to samples collected after '2022-01-01';
- 'have blossomed into large collections' refers to a situation where the average sample ID is greater than 10;
- 'dawn of 2022' refers to '2022-01-01';
- 'processed via Pipeline_X' refers to samples with a pipeline_id that matches the pipeline_id of 'Pipeline_X'.

sql:
SELECT sample_name, sample_collection_date
FROM genomics_samples
ORDER BY sample_collection_date DESC;

SELECT result_summary
FROM genomics_analysis_results
ORDER BY dataset_id, result_id;

SELECT sample_name
FROM genomics_samples
ORDER BY sample_name;
